import{c as e,Q as d,j as n,m as s}from"./chunks/framework.BPKcPtvA.js";const h=JSON.parse('{"title":"Tier matrix","description":"Which tools are allowed in which tier.","frontmatter":{"title":"Tier matrix","description":"Which tools are allowed in which tier."},"headers":[],"relativePath":"reference/tier-matrix.md","filePath":"reference/tier-matrix.md","lastUpdated":1780245214000}'),i={name:"reference/tier-matrix.md"};function a(r,t,l,o,c,y){return d(),n("div",null,[...t[0]||(t[0]=[s('<h1 id="tier-matrix" tabindex="-1">Tier matrix <a class="header-anchor" href="#tier-matrix" aria-label="Permalink to &quot;Tier matrix&quot;">​</a></h1><p>A quick lookup table for whether a given tool runs in each of the five tiered-autonomy states. <strong>Scoped autonomy</strong> is the live autonomous tier (a bounded session key + broker daemon sign within a per-trade cap and TTL, no per-action prompt). <strong>Policy-bound</strong> is a designed automation tier whose encrypted-threshold auto-signing engine is built but disabled in every deployment — selecting it yields an allowlist-scoped tier without a live risk engine (the &quot;if within bounds&quot; auto-signing below describes the design, not current behavior).</p><table tabindex="0"><thead><tr><th>Tool</th><th style="text-align:center;">Advisory</th><th style="text-align:center;">Confirm-per-action</th><th style="text-align:center;">Policy-bound (engine disabled)</th><th style="text-align:center;">Scoped autonomy (live)</th><th style="text-align:center;">Paused</th></tr></thead><tbody><tr><td><code>read.*</code> (all 7)</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td></tr><tr><td><code>position.buy</code></td><td style="text-align:center;">✅ passkey</td><td style="text-align:center;">✅ session key</td><td style="text-align:center;">✅ allowlist-scoped (design: if within bounds)</td><td style="text-align:center;">✅ within cap + TTL</td><td style="text-align:center;">❌ 423</td></tr><tr><td><code>position.sell</code></td><td style="text-align:center;">✅ passkey</td><td style="text-align:center;">✅ session key</td><td style="text-align:center;">✅ allowlist-scoped (design: if within bounds)</td><td style="text-align:center;">✅ within cap + TTL</td><td style="text-align:center;">❌ 423</td></tr><tr><td><code>position.claim</code></td><td style="text-align:center;">✅ passkey</td><td style="text-align:center;">✅ session key</td><td style="text-align:center;">✅ (claim is fee-bearing pull)</td><td style="text-align:center;">✅ within cap + TTL</td><td style="text-align:center;">❌ 423</td></tr><tr><td><code>position.rebalance</code></td><td style="text-align:center;">✅ passkey</td><td style="text-align:center;">✅ session key</td><td style="text-align:center;">✅ allowlist-scoped (design: if within drift bounds)</td><td style="text-align:center;">✅ within cap + TTL</td><td style="text-align:center;">❌ 423</td></tr><tr><td><code>policy.set_tier</code></td><td style="text-align:center;">✅ passkey</td><td style="text-align:center;">✅ passkey (requires re-auth)</td><td style="text-align:center;">✅ passkey</td><td style="text-align:center;">✅ passkey</td><td style="text-align:center;">❌ — except <code>→ resume</code>, which needs passkey</td></tr><tr><td><code>policy.pause</code></td><td style="text-align:center;">✅ idempotent</td><td style="text-align:center;">✅ idempotent</td><td style="text-align:center;">✅ idempotent</td><td style="text-align:center;">✅ idempotent</td><td style="text-align:center;">✅ idempotent (no-op)</td></tr><tr><td><code>policy.audit_export</code></td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td></tr><tr><td><code>policy.session_key_status</code></td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td></tr><tr><td><code>issuer.distribute_yield</code></td><td style="text-align:center;">✅ passkey</td><td style="text-align:center;">✅ session key</td><td style="text-align:center;">✅ allowlist-scoped (design: if within issuer-side bounds)</td><td style="text-align:center;">✅ within cap + TTL</td><td style="text-align:center;">❌ 423</td></tr><tr><td><code>issuer.kyc_add</code></td><td style="text-align:center;">✅ passkey</td><td style="text-align:center;">✅ session key</td><td style="text-align:center;">✅ allowlist-scoped (design: if within bounds)</td><td style="text-align:center;">✅ within cap + TTL</td><td style="text-align:center;">❌ 423</td></tr><tr><td><code>issuer.kyc_remove</code></td><td style="text-align:center;">✅ passkey</td><td style="text-align:center;">✅ session key</td><td style="text-align:center;">✅ allowlist-scoped (design: if within bounds)</td><td style="text-align:center;">✅ within cap + TTL</td><td style="text-align:center;">❌ 423</td></tr><tr><td><code>issuer.unpause_token</code></td><td style="text-align:center;">✅ passkey</td><td style="text-align:center;">✅ session key</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅ within cap + TTL</td><td style="text-align:center;">❌ 423</td></tr><tr><td><code>issuer.audit_query</code></td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td></tr><tr><td><code>governance.propose</code></td><td style="text-align:center;">✅ passkey</td><td style="text-align:center;">✅ session key</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">❌ 423</td></tr><tr><td><code>governance.cast_vote</code></td><td style="text-align:center;">✅ passkey</td><td style="text-align:center;">✅ session key</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">❌ 423</td></tr></tbody></table><p><strong>Legend:</strong></p><ul><li>✅ <strong>passkey</strong> — Action signed by your master passkey via WebAuthn ceremony.</li><li>✅ <strong>session key</strong> — Action signed by your scoped session key (no WebAuthn re-prompt for ~1h).</li><li>✅ <strong>within cap + TTL</strong> — Scoped autonomy: the broker daemon signs without prompting as long as the trade is within your per-trade cap and the session key&#39;s TTL hasn&#39;t expired.</li><li>✅ <strong>allowlist-scoped (design: if within bounds)</strong> — Policy-bound: the action is allowed within the tier&#39;s allowlist scope. The encrypted-threshold auto-signing engine (&quot;if within bounds&quot;) is built but disabled in every deployment, so the bounds check is not driven today.</li><li>✅ <strong>idempotent</strong> — Always allowed regardless of state.</li><li>❌ <strong>423</strong> — Returns <code>423 PAUSED</code>. Read tools still work.</li></ul><h2 id="tier-transition-matrix" tabindex="-1">Tier transition matrix <a class="header-anchor" href="#tier-transition-matrix" aria-label="Permalink to &quot;Tier transition matrix&quot;">​</a></h2><table tabindex="0"><thead><tr><th>From → To</th><th style="text-align:center;">Allowed</th><th>Signer required</th></tr></thead><tbody><tr><td>Advisory → Confirm-per-action</td><td style="text-align:center;">✅</td><td>Passkey (signs new session-key validator install)</td></tr><tr><td>Advisory → Policy-bound</td><td style="text-align:center;">✅</td><td>Passkey + allowlist scope (encrypted threshold setup is part of the disabled design)</td></tr><tr><td>Advisory → Scoped autonomy</td><td style="text-align:center;">✅</td><td>Passkey (signs bounded session-key install: per-trade cap + TTL)</td></tr><tr><td>Advisory → Paused</td><td style="text-align:center;">✅</td><td>None (always allowed)</td></tr><tr><td>Confirm-per-action → Advisory</td><td style="text-align:center;">✅</td><td>Passkey (uninstalls validator)</td></tr><tr><td>Confirm-per-action → Policy-bound</td><td style="text-align:center;">✅</td><td>Passkey + allowlist scope</td></tr><tr><td>Confirm-per-action → Scoped autonomy</td><td style="text-align:center;">✅</td><td>Passkey (signs bounded session-key install)</td></tr><tr><td>Confirm-per-action → Paused</td><td style="text-align:center;">✅</td><td>None</td></tr><tr><td>Policy-bound → Advisory</td><td style="text-align:center;">✅</td><td>Passkey (clears scope)</td></tr><tr><td>Policy-bound → Confirm-per-action</td><td style="text-align:center;">✅</td><td>Passkey</td></tr><tr><td>Policy-bound → Scoped autonomy</td><td style="text-align:center;">✅</td><td>Passkey (signs bounded session-key install)</td></tr><tr><td>Policy-bound → Paused</td><td style="text-align:center;">✅</td><td>None (manual)</td></tr><tr><td>Scoped autonomy → Advisory</td><td style="text-align:center;">✅</td><td>Passkey (revokes bounded session key)</td></tr><tr><td>Scoped autonomy → Confirm-per-action</td><td style="text-align:center;">✅</td><td>Passkey</td></tr><tr><td>Scoped autonomy → Paused</td><td style="text-align:center;">✅</td><td>None (always allowed; <code>/pause</code> revokes the session key)</td></tr><tr><td>Paused → Advisory</td><td style="text-align:center;">✅</td><td>Passkey (reinstalls session-key validator)</td></tr><tr><td>Paused → Confirm-per-action</td><td style="text-align:center;">✅</td><td>Passkey</td></tr><tr><td>Paused → Policy-bound</td><td style="text-align:center;">✅</td><td>Passkey + allowlist scope</td></tr><tr><td>Paused → Scoped autonomy</td><td style="text-align:center;">✅</td><td>Passkey (signs bounded session-key install)</td></tr></tbody></table><h2 id="breach-→-auto-pause-designed-not-driven" tabindex="-1">Breach → auto-pause (designed, not driven) <a class="header-anchor" href="#breach-→-auto-pause-designed-not-driven" aria-label="Permalink to &quot;Breach → auto-pause (designed, not driven)&quot;">​</a></h2><p>In the Policy-bound design, a breach (any of: max drawdown, daily spend, min yield, drift tolerance) would trigger an auto-pause. The breach-and-auto-pause path is present in the contracts but is <strong>not driven in any deployment</strong> today, because the encrypted-threshold engine that detects breaches is disabled. The cascade and reasoning live in <a href="/policy/tiered-autonomy">Tiered autonomy → Policy-bound</a>. The live autonomous tier — Scoped autonomy — bounds risk instead via a per-trade cap and session-key TTL rather than a running breach engine.</p><h2 id="where-next" tabindex="-1">Where next <a class="header-anchor" href="#where-next" aria-label="Permalink to &quot;Where next&quot;">​</a></h2><ul><li><a href="/policy/tiered-autonomy">Tiered autonomy</a> — what each tier means.</li><li><a href="/reference/tool-catalog">Tool catalog</a> — what each tool does.</li><li><a href="/policy/pause">The /pause kill-switch</a> — the always-on escape hatch.</li></ul>',11)])])}const p=e(i,[["render",a]]);export{h as __pageData,p as default};
